import { Vex } from '@vex_dev/sdk';
import { ChatFlowiseCallbackHandler } from 'flowise';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY,
  projectId: 'coding-assistant',
  riskProfile: 'medium'
});

const flowiseHandler = new ChatFlowiseCallbackHandler({
  onChainStart: async (inputs) => {
    await vex.startSpan({
      name: 'coding-assistant-flow',
      input: inputs,
      metadata: { repo: inputs.repoUrl }
    });
  },
  onChainEnd: async (output) => {
    const result = await vex.verify({
      output,
      checks: ['code_correctness', 'security_vulnerability'],
      context: { language: 'typescript' }
    });
    return result.approved ? output : result.fallback;
  }
});

// Attach to Flowise chatflow
const chatflow = await loader.getChatflow();
chatflow.callbacks = [flowiseHandler];

import { VectorStoreRetriever } from 'flowise';

const retrieverNode = new VectorStoreRetriever({
  vectorStore: chromaStore,
  k: 5
});

retrieverNode.callbacks = [{
  onRetrieverEnd: async (documents, query) => {
    const scores = await vex.score({
      input: query,
      output: documents.map(d => d.pageContent),
      check: 'semantic_relevance',
      threshold: 0.7
    });

    return documents.filter((_, i) => scores[i] > 0.7);
  }
}];

import { PythonREPLTool } from 'flowise/tools';

const secureREPL = new PythonREPLTool();

secureREPL.callbacks = [{
  handleToolStart: async (toolInput: string) => {
    const scan = await vex.verify({
      output: toolInput,
      checks: [
        'no_credential_leakage',
        'no_system_calls',
        'dependency_safety',
        'license_compliance'
      ]
    });

    if (!scan.approved) {
      throw new Error(`Security violation: ${scan.issues[0]}`);
    }
    return toolInput;
  }
}];

import { AgentExecutor } from 'flowise';

const validatorAgent = new AgentExecutor({
  llm: openaiChat,
  tools: [testRunner],
  systemPrompt: `You are a code validator. Only approve code that:
1. Passes all unit tests
2. Has no security issues
3. Uses safe dependencies
Respond ONLY with APPROVED or REJECTED.`
});

validatorAgent.callbacks = [{
  onAgentAction: async (action) => {
    const testResult = await vex.verify({
      output: action.toolInput,
      checks: ['test_passed'],
      context: { repo: 'current' }
    });
    return testResult.approved;
  }
}];

