import { Vex } from '@vex_dev/sdk';

export const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'flowise-coding-assistant',
  riskProfile: 'medium',
  defaultChecks: [
    'code_correctness',
    'security_vulnerability_scanning',
    'no_credential_leakage',
    'dependency_safety',
    'license_compliance'
  ]
});

import type { BaseChatMessage, CallbackManager } from 'flowise';

export class VexFlowiseHandler implements CallbackManager {
  async onChainEnd(output: string, runId?: string): Promise<string> {
    const result = await vex.verify({
      spanId: runId,
      output,
      context: {
        useCase: 'ai-coding-assistant',
        framework: 'flowise',
        language: 'typescript'
      }
    });

    return result.approved ? output : `Validation failed: ${result.reason}`;
  }

  async onError(error: Error): Promise<void> {
    await vex.recordError(error.message, { tags: ['flowise', 'coding'] });
  }
}

export async function verifyCodeOutput(code: string, repoContext: string): Promise<VexResult> {
  return vex.verify({
    output: code,
    input: repoContext,
    checks: {
      code_correctness: {
        parser: 'typescript',
        validateSemantics: true
      },
      security_vulnerability_scanning: {
        scanFor: ['sql-injection', 'xss', 'command-injection']
      },
      no_credential_leakage: {
        patterns: ['process.env', 'apiKey', 'secret']
      },
      dependency_safety: {
        maxVulnerabilities: 0
      }
    }
  });
}
